public double evaluate(double x, double epsilon, int maxIterations) { 

if (x == 0) return 0; 

double result = x; 

double slope = 1; 

double delta = 0; 

int n = 0; 

while (n < maxIterations && epsilon < Math.abs(delta)) { 

result = Math.exp(slope * -x); 

slope *= -x; 

delta = slope * result - epsilon; 

n++; 

} 

if (n == maxIterations) throw new MaxCountExceededException(LocalizedFormats.CONTINUED_FRACTION_INFINITY_DIVERGENCE, x); 

return Math.exp(slope) * result; 

}
